<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #0b0c10;
    --panel: #16181d;
    --border: #2a2d34;
    --text: #d7d9dd;
    --accent: #4f8cff;
  }
  * { box-sizing: border-box; }
  html, body {
    height: 100%;
    margin: 0;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, "Segoe UI", Roboto, Arial, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 18px;
    padding: 20px;
  }
  h1 {
    font-size: 18px;
    font-weight: 600;
    letter-spacing: 0.5px;
    margin: 0;
    color: #9aa4b2;
  }
  #stage {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 14px;
  }
  #canvas-wrap {
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 8px;
    background: var(--panel);
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
  }
  #sand {
    display: block;
    background: #101014;
    border-radius: 4px;
    cursor: crosshair;
    image-rendering: pixelated;
  }
  #controls {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;
    max-width: 560px;
  }
  .mat-btn {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    border-radius: 8px;
    border: 1px solid var(--border);
    background: var(--panel);
    color: var(--text);
    font-size: 13px;
    cursor: pointer;
    transition: transform 0.08s ease, border-color 0.15s ease, background 0.15s ease;
  }
  .mat-btn:hover { transform: translateY(-1px); border-color: #40444d; }
  .mat-btn.active {
    border-color: var(--accent);
    background: #1c2230;
    box-shadow: 0 0 0 1px var(--accent) inset;
  }
  .swatch {
    width: 14px;
    height: 14px;
    border-radius: 3px;
    display: inline-block;
    border: 1px solid rgba(255,255,255,0.15);
  }
  #clear {
    padding: 8px 16px;
    border-radius: 8px;
    border: 1px solid #5a2b2b;
    background: #2a1414;
    color: #ffb4b4;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s ease;
  }
  #clear:hover { background: #3a1a1a; }
  #hint {
    font-size: 12px;
    color: #6b7280;
    text-align: center;
  }
</style>
</head>
<body>

<h1>Falling Sand Sandbox</h1>

<div id="stage">
  <div id="canvas-wrap">
    <canvas id="sand" width="500" height="500"></canvas>
  </div>

  <div id="controls">
    <button class="mat-btn active" id="mat-sand"><span class="swatch" style="background:#d9b35c"></span>Sand</button>
    <button class="mat-btn" id="mat-water"><span class="swatch" style="background:#3a7bd5"></span>Water</button>
    <button class="mat-btn" id="mat-wall"><span class="swatch" style="background:#7a7f8a"></span>Wall</button>
    <button class="mat-btn" id="mat-acid"><span class="swatch" style="background:#7fe33a"></span>Acid</button>
    <button class="mat-btn" id="mat-empty"><span class="swatch" style="background:#101014;border-style:dashed"></span>Eraser</button>
    <button id="clear">Clear</button>
  </div>

  <div id="hint">Click and drag on the canvas to paint. Pick a material above.</div>
</div>

<script>
(function(){
  "use strict";

  // ---------- grid setup ----------
  const W = 100, H = 100;
  const CELL = 5; // px per cell -> 500x500 canvas (>=400x400)

  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  const NAME_BY_CODE = ["empty", "sand", "water", "wall", "acid"];
  const CODE_BY_NAME = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  const COLORS = {
    [EMPTY]: "#101014",
    [SAND]:  "#d9b35c",
    [WATER]: "#3a7bd5",
    [WALL]:  "#7a7f8a",
    [ACID]:  "#7fe33a"
  };

  let grid = new Uint8Array(W * H);
  let moved = new Uint8Array(W * H);
  // static per-cell noise for subtle texture shading
  const noise = new Float32Array(W * H);
  for (let i = 0; i < W * H; i++) noise[i] = Math.random();

  function idx(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  function moveCell(fromId, toId) {
    grid[toId] = grid[fromId];
    grid[fromId] = EMPTY;
    moved[toId] = 1;
  }
  function swapCell(aId, bId) {
    const tmp = grid[aId];
    grid[aId] = grid[bId];
    grid[bId] = tmp;
    moved[aId] = 1;
    moved[bId] = 1;
  }

  function stepSand(x, y, id) {
    if (y + 1 < H) {
      const bid = idx(x, y + 1);
      const b = grid[bid];
      if (b === EMPTY) { moveCell(id, bid); return; }
      if (b === WATER || b === ACID) { swapCell(id, bid); return; }
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx, ny = y + 1;
      if (inBounds(nx, ny)) {
        const nid = idx(nx, ny);
        const n = grid[nid];
        if (n === EMPTY) { moveCell(id, nid); return; }
        if (n === WATER || n === ACID) { swapCell(id, nid); return; }
      }
    }
    moved[id] = 1;
  }

  function stepWater(x, y, id) {
    if (y + 1 < H) {
      const bid = idx(x, y + 1);
      if (grid[bid] === EMPTY) { moveCell(id, bid); return; }
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx, ny = y + 1;
      if (inBounds(nx, ny) && grid[idx(nx, ny)] === EMPTY) { moveCell(id, idx(nx, ny)); return; }
    }
    for (const dx of dirs) {
      const nx = x + dx, ny = y;
      if (inBounds(nx, ny) && grid[idx(nx, ny)] === EMPTY) { moveCell(id, idx(nx, ny)); return; }
    }
    moved[id] = 1;
  }

  function stepAcid(x, y, id) {
    if (y + 1 < H) {
      const bid = idx(x, y + 1);
      const b = grid[bid];
      if (b === EMPTY) { moveCell(id, bid); return; }
      if (b === WATER) { swapCell(id, bid); return; }
      if (b === SAND || b === WALL) { grid[bid] = EMPTY; moved[id] = 1; moved[bid] = 1; return; }
    }
    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx, ny = y + 1;
      if (inBounds(nx, ny)) {
        const nid = idx(nx, ny);
        const n = grid[nid];
        if (n === EMPTY) { moveCell(id, nid); return; }
        if (n === WATER) { swapCell(id, nid); return; }
        if (n === SAND || n === WALL) { grid[nid] = EMPTY; moved[id] = 1; moved[nid] = 1; return; }
      }
    }
    for (const dx of dirs) {
      const nx = x + dx, ny = y;
      if (inBounds(nx, ny)) {
        const nid = idx(nx, ny);
        const n = grid[nid];
        if (n === EMPTY) { moveCell(id, nid); return; }
        if (n === SAND || n === WALL) { grid[nid] = EMPTY; moved[id] = 1; moved[nid] = 1; return; }
      }
    }
    moved[id] = 1;
  }

  function step() {
    moved.fill(0);
    for (let y = H - 1; y >= 0; y--) {
      const leftToRight = Math.random() < 0.5;
      for (let i = 0; i < W; i++) {
        const x = leftToRight ? i : (W - 1 - i);
        const id = idx(x, y);
        if (moved[id]) continue;
        const c = grid[id];
        if (c === EMPTY || c === WALL) continue;
        if (c === SAND) stepSand(x, y, id);
        else if (c === WATER) stepWater(x, y, id);
        else if (c === ACID) stepAcid(x, y, id);
      }
    }
  }

  // ---------- rendering ----------
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");
  canvas.width = W * CELL;
  canvas.height = H * CELL;
  canvas.style.width = (W * CELL) + "px";
  canvas.style.height = (H * CELL) + "px";

  function shade(hex, amt) {
    const n = parseInt(hex.slice(1), 16);
    let r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
    r = Math.max(0, Math.min(255, r + amt));
    g = Math.max(0, Math.min(255, g + amt));
    b = Math.max(0, Math.min(255, b + amt));
    return "rgb(" + r + "," + g + "," + b + ")";
  }

  function render() {
    ctx.fillStyle = COLORS[EMPTY];
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const id = idx(x, y);
        const c = grid[id];
        if (c === EMPTY) continue;
        const base = COLORS[c];
        const variance = (noise[id] - 0.5) * 30;
        ctx.fillStyle = shade(base, variance);
        ctx.fillRect(x * CELL, y * CELL, CELL, CELL);
      }
    }
  }

  // ---------- public API ----------
  window.sim = {
    w: W,
    h: H,
    tick(n) {
      n = n || 1;
      for (let i = 0; i < n; i++) step();
    },
    get(x, y) {
      if (!inBounds(x, y)) return "empty";
      return NAME_BY_CODE[grid[idx(x, y)]];
    },
    set(x, y, material) {
      if (!inBounds(x, y)) return;
      const code = CODE_BY_NAME[material];
      if (code === undefined) return;
      grid[idx(x, y)] = code;
    },
    clear() {
      grid.fill(EMPTY);
    }
  };

  // ---------- UI ----------
  let currentMaterial = SAND;
  const buttons = {
    "mat-sand": SAND,
    "mat-water": WATER,
    "mat-wall": WALL,
    "mat-acid": ACID,
    "mat-empty": EMPTY
  };

  Object.keys(buttons).forEach(function(id) {
    const btn = document.getElementById(id);
    btn.addEventListener("click", function() {
      currentMaterial = buttons[id];
      document.querySelectorAll(".mat-btn").forEach(function(b) { b.classList.remove("active"); });
      btn.classList.add("active");
    });
  });

  document.getElementById("clear").addEventListener("click", function() {
    window.sim.clear();
  });

  // painting
  let painting = false;
  const BRUSH_RADIUS = 2;

  function paintAt(clientX, clientY) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const px = (clientX - rect.left) * scaleX;
    const py = (clientY - rect.top) * scaleY;
    const cx = Math.floor(px / CELL);
    const cy = Math.floor(py / CELL);
    for (let dy = -BRUSH_RADIUS; dy <= BRUSH_RADIUS; dy++) {
      for (let dx = -BRUSH_RADIUS; dx <= BRUSH_RADIUS; dx++) {
        const x = cx + dx, y = cy + dy;
        if (dx * dx + dy * dy <= BRUSH_RADIUS * BRUSH_RADIUS && inBounds(x, y)) {
          grid[idx(x, y)] = currentMaterial;
        }
      }
    }
  }

  canvas.addEventListener("mousedown", function(e) {
    painting = true;
    paintAt(e.clientX, e.clientY);
  });
  window.addEventListener("mouseup", function() { painting = false; });
  canvas.addEventListener("mouseleave", function() { /* keep painting state until mouseup */ });
  canvas.addEventListener("mousemove", function(e) {
    if (painting) paintAt(e.clientX, e.clientY);
  });

  // touch support
  canvas.addEventListener("touchstart", function(e) {
    painting = true;
    const t = e.touches[0];
    paintAt(t.clientX, t.clientY);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener("touchmove", function(e) {
    if (painting) {
      const t = e.touches[0];
      paintAt(t.clientX, t.clientY);
    }
    e.preventDefault();
  }, { passive: false });
  window.addEventListener("touchend", function() { painting = false; });

  // ---------- animation loop ----------
  function loop() {
    step();
    render();
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);

})();
</script>

</body>
</html>
